import platform
import time
import datetime
import base64
import tempfile
import socket  # Added for communicating with the SIEM
from pygame import mixer
from plyer import notification

# MP3 encoded in Base64 format
BASE64_MP3 = """
"""

# ----------------------------------------------------------------
# SIEM SERVER CONFIGURATION
# ----------------------------------------------------------------
SIEM_SERVER_IP = "192.0.2.1"  # <-- Replace with your SIEM server IP
SYSLOG_PORT = 514
# ----------------------------------------------------------------
# ----------------------------------------------------------------

try:
    startup_hostname = socket.gethostname()
    startup_time = datetime.datetime.now().strftime('%b %d %H:%M:%S')
    startup_msg = f"<14>{startup_time} {startup_hostname} kernel: WINDOWS SYSTEM CONNECTED TO SIEM SEVER\n"
    with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as sock:
        sock.sendto(startup_msg.encode('utf-8'), (SIEM_SERVER_IP, SYSLOG_PORT))
except Exception as e:
        print(f"Startup logging failed: {e}")

def send_to_siem_dashboard(action, device_info):
    """
    Formats the USB event to mimic standard system logs and transmits 
    it directly to the rsyslog listener on the central server.
    """
    try:
        hostname = socket.gethostname()
        timestamp = datetime.datetime.now().strftime('%b %d %H:%M:%S')
        
        log_message = f"<14>{timestamp} {hostname} kernel: WINDOWS_USB_ALERT [Action={action}] {device_info}\n"
            
        with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as sock:
            sock.sendto(log_message.encode('utf-8'), (SIEM_SERVER_IP, SYSLOG_PORT))
    except Exception as e:
        print(f"Network logging failed: {e}")


def play_alert_sound():
    """Decodes the embedded MP3 asset and triggers the sound card"""
    try:
        mixer.init()
        with tempfile.NamedTemporaryFile(delete=False, suffix=".mp3") as tmp:
            tmp.write(base64.b64decode(BASE64_MP3))
            tmp_path = tmp.name
        
        mixer.music.load(tmp_path)
        mixer.music.play()
        while mixer.music.get_busy():
            time.sleep(0.1)
        mixer.quit()
    except Exception as e:
        print(f"Audio Error: {e}")

def alert_usb_connection(action, device_info):
    """Triggers local notifications, plays audio, and alerts the central dashboard"""
    # 1. Immediately report the threat to the central SIEM Dashboard
    send_to_siem_dashboard(action, device_info)
    
    # 2. Fire local desktop banner notification
    notification.notify(
        title="🛡️ SIEM Endpoint Alert",
        message=f"USB Activity Blocked: {device_info} has been {action}ed.",
        app_name="SIEM Agent"
    )
    
    # 3. Play the warning siren sound
    play_alert_sound()

def log_usb_activity(action, device_info):
    """For quieter actions (like device removals), we report it to the SIEM without a siren sound"""
    send_to_siem_dashboard(action, device_info)

# PLATFORM DETECTION LOOPS

if platform.system() == "Windows":
    import win32api
    
    def get_drive_name(letter):
        return letter
        
    drives = set(win32api.GetLogicalDriveStrings().split("\000")[:-1])
    print(f"Monitoring Windows USB devices... Reporting to SIEM at {SIEM_SERVER_IP}")

    while True:
        new_drives = set(win32api.GetLogicalDriveStrings().split("\000")[:-1])
        added = new_drives - drives
        removed = drives - new_drives

        if added:
            for drive in added:
                alert_usb_connection("add", f"Drive {get_drive_name(drive)}")
        if removed:
            for drive in removed:
                log_usb_activity("remove", f"Drive {get_drive_name(drive)}")

        drives = new_drives
        time.sleep(2)
